// Anti-bot: check honeypot
const d = $input.first().json.body || $input.first().json;
if (d.website) {
  // Bot filled the honeypot field
  return [{ json: { blocked: true, reason: 'honeypot' } }];
}

const text = (d.text || '').trim();
const type = (d.type || 'otro').trim();
const sector = (d.sector || '').trim();

// Validation
if (!text || text.length < 10) {
  return [{ json: { blocked: true, reason: 'too_short' } }];
}
if (text.length > 300) {
  return [{ json: { blocked: true, reason: 'too_long' } }];
}

// Sanitize: only allow safe chars (letters, numbers, basic punctuation)
// Strip HTML, formulas, control characters
let clean = text
  .replace(/<[^>]*>/g, '')           // strip HTML tags
  .replace(/[\x00-\x08\x0B\x0C\x0E-\x1F\x7F]/g, '') // control chars
  .replace(/[{}\[\]\\|`~^]/g, '')    // dangerous chars
  .trim();

// Escape Google Sheets formula injection
if (/^[=+\-@]/.test(clean)) {
  clean = "'" + clean;
}

if (clean.length < 10) {
  return [{ json: { blocked: true, reason: 'sanitized_too_short' } }];
}

const now = new Date();
return [{ json: {
  blocked: false,
  timestamp: now.toISOString(),
  date: now.toLocaleDateString('es-ES'),
  time: now.toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' }),
  type: ['sugerencia', 'bug', 'otro'].includes(type) ? type : 'otro',
  sector: sector.substring(0, 30),
  text: clean.substring(0, 300),
} }];
